import type { Meta } from '@storybook/react';
import * as React from 'react';
import { Text, Divider, Select, Input } from '@universe-design/react';
export { FontFamilyTest } from './fontFamily';
export { QuoteText } from './quoteTest';

export default {
  title: 'Business Scene / Font',
} as Meta;

export const CircularFontWeightTest = () => {
  const fontWeights = [100, 200, 300, 400, 500, 600, 700, 800, 900];
  const fontFamilys = [
    {
      label: 'new-zh-CN',
      value: `LarkHackSafariFont, LarkEmojiFont, LarkChineseQuote,
    Lark Circular, system-ui, Helvetica Neue, Tahoma, PingFang SC, Microsoft Yahei,
    Arial, Hiragino Sans GB, sans-serif, Apple Color Emoji, Segoe UI Emoji,
    Segoe UI Symbol, Noto Color Emoji`,
    },
    {
      label: 'new-en-US',
      value: `LarkHackSafariFont, LarkEmojiFont, LarkChineseQuote,
    Lark Circular, system-ui, Helvetica Neue, Tahoma, PingFang SC, Microsoft Yahei,
    Arial, Hiragino Sans GB, sans-serif, Apple Color Emoji, Segoe UI Emoji,
    Segoe UI Symbol, Noto Color Emoji`,
    },
    {
      label: 'new-ja-JP',
      value: `LarkHackSafariFont, "ヒラギノ角ゴシック", "Yu Gothic UI",
    "Microsoft Jhenghei UI", "Microsoft Yahei UI", "ＭＳ Ｐゴシック", PingFang SC,
    Hiragino Sans GB, Arial, sans-serif, Apple Color Emoji, Segoe UI Emoji,
    Segoe UI Symbol, Noto Color Emoji`,
    },
    {
      label: 'Online-zh-CN',
      value: `LarkHackSafariFont, LarkEmojiFont, LarkChineseQuote,
      -apple-system, BlinkMacSystemFont, Helvetica Neue, Tahoma, PingFang SC,
      Microsoft Yahei, Arial, Hiragino Sans GB, sans-serif, Apple Color Emoji,
      Segoe UI Emoji, Segoe UI Symbol, Noto Color Emoji`,
    },
    {
      label: 'Online-en-US',
      value: `LarkHackSafariFont, LarkEmojiFont, LarkChineseQuote,  -apple-system,
      BlinkMacSystemFont, Helvetica Neue, Tahoma, PingFang SC, Microsoft Yahei,
      Arial, Hiragino Sans GB, sans-serif, Apple Color Emoji, Segoe UI Emoji,
      Segoe UI Symbol, Noto Color Emoji`,
    },
    {
      label: 'Online-ja-JP',
      value: `LarkHackSafariFont,"ヒラギノ角ゴシック","Yu Gothic UI","Microsoft Jhenghei UI","Microsoft Yahei UI",
      "ＭＳ Ｐゴシック",PingFang SC,Hiragino Sans GB,Arial,sans-serif,Apple Color Emoji,Segoe UI Emoji,Segoe UI Symbol,Noto Color Emoji`,
    },
  ];

  const defaultTestText = '字体测试文档 English セッティングエリア Ỏ Ẳ ประเทศไทย ѳ у 한국어 औ ध भ';
  const [text, setText] = React.useState(defaultTestText);
  const [fontFamily, setFontFamily] = React.useState(fontFamilys[0].value);
  const [lang, setLang] = React.useState('en');

  const str2SpanList = (s: string, sep?: RegExp) =>
    s.split(sep ? sep : '').map((ch, index) => (
      <span key={ch + index}>
        <span>{ch}</span>
      </span>
    ));

  return (
    <div>
      <Divider text="设置区" />
      Lang:{' '}
      <Select
        options={[{ value: 'zh' }, { value: 'ja' }, { value: 'en' }]}
        value={lang}
        onChange={v => setLang(v || '')}
        mode="single"
      />
      FontFamily:{' '}
      <Select
        options={fontFamilys}
        value={fontFamily}
        onChange={v => setFontFamily(v || '')}
        mode="single"
        style={{ width: 300 }}
      />
      <div>
        <Text>测试文本： </Text>
        <Input.TextArea value={text} onChange={e => setText(e.target.value)} />
      </div>
      <Divider text="预览区" />
      <Text>
        {' '}
        已选择语言： {lang} 已选择渲染使用字体：{fontFamily}
      </Text>
      {fontWeights.map(fw => (
        <p key={fw} style={{ fontWeight: fw, fontFamily }}>
          font-weight: {fw} {str2SpanList(text)}
        </p>
      ))}
    </div>
  );
};

export const CircularFontSizeTest = () => {
  const fontSizes = [14, 15, 16, 17, 18, 19, 20, 21, 22];

  const defaultTestText = '字体测试文档 English セッティングエリア Ỏ Ẳ ประเทศไทย ѳ у 한국어 औ ध भ';
  const [text, setText] = React.useState(defaultTestText);

  const str2SpanList = (s: string, sep?: RegExp) =>
    s.split(sep ? sep : '').map((ch, index) => (
      <span key={ch + index}>
        <span>{ch}</span>
      </span>
    ));

  return (
    <div>
      <div>
        <Text>测试文本： </Text>
        <Input.TextArea value={text} onChange={e => setText(e.target.value)} />
      </div>
      <Divider text="预览区" />
      <Divider text="Tahoma + Microsoft Yahei" />

      {fontSizes.map(fs => (
        <p key={fs} style={{ fontSize: fs, fontFamily: 'Tahoma, 雅黑' }}>
          font-size: {fs} {str2SpanList(text)}
        </p>
      ))}
      <Divider text="Circular + Microsoft Yahei" />
      {fontSizes.map(fs => (
        <p key={fs} style={{ fontSize: fs, fontFamily: 'Lark Circular, 雅黑' }}>
          font-size: {fs} {str2SpanList(text)}
        </p>
      ))}
    </div>
  );
};
